UPDATE stage_prompts SET config = '{"stage": 2, "laneTitle": "Story Board", "assemblyOrder": ["masterSheetPrompt", "yourDescription", "universalStyle"], "universalStyle": {"key": "production_bible_universal", "label": "Universal Production Bible Style", "text": "GLOBAL ART DIRECTION\n\nEvery generated storyboard belongs to the same Production Bible.\n\nVisual Identity\n\u2022 Apple keynote quality\n\u2022 A24 cinematic minimalism\n\u2022 Pixar pre-production documentation\n\u2022 Weta Workshop production bible\n\u2022 Netflix concept art presentation\n\u2022 Cannes Lions advertising pitch deck\n\nGraphic Language\n\u2022 White premium presentation layout\n\u2022 Thin black divider lines\n\u2022 Spacious negative space\n\u2022 Editorial typography hierarchy\n\u2022 Soft paper texture\n\u2022 Production asset numbering\n\u2022 Revision labels\n\u2022 Version numbers\n\u2022 Project title placeholder\n\u2022 Copyright footer\n\nEvery storyboard should feel like it was created by an elite commercial art department."}, "items": {"story": {"label": "Story", "note": "No editable fields \u2014 the customer already decided the story, dialogue, and tone in the (now-locked) Stage 1 brief. The designer''s job here is compiling that into a Flow-ready storyboard prompt, not re-authoring a concept/tone.", "content": {"geminiInstruction": "There is nothing to fill in beyond the \"prompt\" field \u2014 the brief''s \"storyboard\" field is the customer''s own already-written script and the brief''s \"tone\" field is the already-decided mood; both are locked and must be used exactly as given, never re-interpreted or summarized into a new concept. Preserve the storyboard''s actual dialogue lines, character names, and scene beats, in the same language/script they were written in \u2014 never translate them to English. Structure the \"prompt\" field as a numbered list of scenes/panels, one per beat from the script, so a designer can review and edit each individually \u2014 the number should match however many real beats the script has (do not force it to a fixed count). Carry the actual dialogue as an on-screen caption or spoken line wherever the script already has one.", "fieldsSchema": [], "autoPopulate": {"note": "One Story generation drafts the skeleton of every downstream stage instead of the designer re-typing every cast member/prop/scene by hand. Each array item becomes a real item in that stage, pre-filled with this description \u2014 the designer still reviews/edits/regenerates each one individually at its own stage afterward. This is new \u2014 nothing in the app reads these fields yet; wiring it up is a ''clean the code'' task.", "geminiResponseFields": [{"key": "characters", "shape": "array of {name, description} \u2014 one entry per distinct person; if multiple people appear together (a couple, a family, friends), give each their own separate entry (e.g. ''Husband'', ''Wife'') \u2014 never merge more than one person into a single entry like ''Couple''", "createsItemsIn": {"stage": 3, "itemKey": "character"}}, {"key": "properties", "shape": "array of {name, description}", "createsItemsIn": {"stage": 3, "itemKey": "property"}}, {"key": "backgrounds", "shape": "array of {name, description}", "createsItemsIn": {"stage": 3, "itemKey": "background"}}, {"key": "sounds", "shape": "array of {name, description}", "createsItemsIn": {"stage": 3, "itemKey": "sound"}}, {"key": "scenes", "shape": "array of {name, location, action, dialogue, emotion} \u2014 one entry per numbered beat in the storyboard; location and action are required for every scene; dialogue should be the exact line from the storyboard if this beat has one (same language, never translated), or omitted if this beat has no dialogue; emotion must be exactly one of: Frustrated, Curious, Relieved, Happy, Excited, Confident, Calm", "createsItemsIn": {"stage": 4, "itemKey": "scene"}}]}}, "outputInstructions": [{"key": "master_storyboard_prompt", "label": "Master Storyboard Prompt", "default": true, "text": "Create a premium cinematic storyboard SHEET containing ONE PANEL PER NUMBERED SCENE/BEAT in the description below \u2014 never merge multiple beats into a single panel, and never stop after only the first panel. If the description lists 4 numbered beats, render exactly 4 panels, laid out in sequence order on the same sheet.\n\nOBJECTIVE\nVisualize every numbered scene/beat exactly as written, each as its own separate panel.\nDo not invent additional story elements.\nDo not skip, merge, or truncate any beat \u2014 every numbered beat in the description gets its own panel.\nMaintain the described characters, props, environment, emotion and action, panel by panel.\n\nGenerate a production-ready multi-panel storyboard suitable for a world-class advertising campaign, clean enough to hand to a client with no further edits.\n\nSTYLE\n\u2022 Hollywood commercial storyboard\n\u2022 Cannes Lions presentation quality\n\u2022 Director''s storyboard\n\u2022 Hand-drawn pencil illustration\n\u2022 Marker rendering\n\u2022 Loose confident sketch lines\n\u2022 Grayscale shading\n\u2022 Slight blue storyboard pencil accents\n\u2022 Premium beige storyboard paper\n\u2022 Elegant editorial graphic design\n\nFRAME DESIGN (repeat this layout for every panel, incrementing the numbering each time) \u2014 ONLY these fields, nothing else:\n\u2022 Scene Number (increments per panel, matching the beat number)\n\u2022 Location\n\u2022 Time of Day\n\u2022 Dialogue / On-Screen Text\n\nFIELD DISCIPLINE (critical \u2014 this is what keeps the sheet client-ready)\n\u2022 Only draw a frame-design field above if this specific scene''s description actually gives you a real value for it. Never draw an empty, blank, or placeholder labeled box.\n\u2022 If this scene has dialogue or on-screen text, render it as one clean line INSIDE its own labeled Dialogue field at the bottom of that panel \u2014 never float it elsewhere on the panel (not as a floating caption, not overlapping the illustration), and never leave the Dialogue field blank when a line exists.\n\u2022 If this scene has no dialogue or on-screen text, omit the Dialogue field for that panel entirely instead of showing it empty.\n\u2022 Do not invent a Camera Angle, Shot Size, Lens, or Camera Movement field for any panel \u2014 that level of detail isn''t part of this sheet.\n\nANNOTATIONS (per panel, only where the scene description actually supports it)\n\u2022 Character movement\n\u2022 Key prop callouts\n\u2022 Performance notes\n\u2022 Emotional beat\n\u2022 Composition notes\n\u2022 Blocking\n\u2022 Screen direction\n\nCINEMATIC QUALITY\n\u2022 Rule of thirds\n\u2022 Leading lines\n\u2022 Dynamic perspective\n\u2022 Strong silhouettes\n\u2022 Foreground / Midground / Background separation\n\u2022 Dramatic lighting\n\u2022 Motivated light source\n\u2022 Shadow direction\n\u2022 Premium production presentation\n\nCOLOR\nMostly grayscale with subtle blue storyboard pencil and light beige paper.\n\nDO NOT\n\u2022 Change the story\n\u2022 Add characters\n\u2022 Change wardrobe\n\u2022 Change props\n\u2022 Cartoonize\n\u2022 Anime\n\u2022 Comic book style\n\u2022 Photorealistic painting\n\u2022 Over-render\n\u2022 Collapse multiple numbered beats into a single panel\n\u2022 Stop after the first panel \u2014 every numbered beat needs its own panel on the sheet\n\u2022 Draw an empty or placeholder labeled box for any field without real data\n\nDIMENSIONS\nRender at high resolution (minimum 1600px on the longest side), in the aspect ratio matching the target platform \u2014 vertical 9:16 for Reels/Shorts/TikTok, 16:9 for YouTube/landscape.\n\nOUTPUT\nGenerate a multi-panel storyboard SHEET with exactly as many panels as there are numbered scenes/beats in the description below, arranged in sequence order on one sheet, each panel looking like it belongs inside the production bible of a multi-million-dollar commercial, and clean enough to send straight to the client with no touch-ups needed."}]}}}' WHERE stage = 2;
